// ===== VERSÃO CORRIGIDA PARA CODE NODE n8n =====
// Parse da data created_at (formato ISO 8601)
const dataCreated = new Date($input.first().json.created_at);

// Data atual (sem usar {{$now}} no Code Node)
const dataAtual = new Date();

// Calcular diferença em milissegundos
const diferencaMs = dataAtual.getTime() - dataCreated.getTime();

// Converter para dias
const diferencaDias = Math.floor(diferencaMs / (1000 * 60 * 60 * 24));

// Retornar resultado
return [{
  json: {
    created_at: $input.first().json.created_at,
    data_atual: dataAtual.toISOString(),
    diferenca_dias: diferencaDias,
    diferenca_absoluta: Math.abs(diferencaDias)
  }
}];

